    print(f"  ORDER BLOCKS (Unfilled)")
    print(f"{'-'*55}")
    if obs:
        for o in obs:
            d = "^" if o["type"]=="BULLISH" else "v"
            print(f"  {o['type']:8s} {d} ${o['bot']:.2f} - ${o['top']:.2f}  [{o['dt']}]")
    else:
        print("  Tidak ada OB unfilled")

