def fetch_candles(symbol="USD/JPY", interval="1h", count=200):
    r = requests.get(f"{BASE}/time_series", params={
        "symbol": symbol, "interval": interval,
        "outputsize": count, "apikey": API_KEY
    }, timeout=15).json()
    if "values" not in r:
        print(f"Error fetching {interval}: {r.get('message','?')}")
        return []
    return [{"datetime": v["datetime"], "open": float(v["open"]),
             "high": float(v["high"]), "low": float(v["low"]),
             "close": float(v["close"])} for v in reversed(r["values"])]


def fetch_price(symbol="USD/JPY"):
    r = requests.get(f"{BASE}/quote?symbol={symbol}&apikey={API_KEY}", timeout=10).json()
    if "close" in r:
        return float(r["close"]), r
    return None, None


# ═══════════════════════════════════════════════════════════
#  SWING POINTS
