def find_swings(candles, n=3):
    sh, sl = [], []
    for i in range(n, len(candles) - n):
        h, l = candles[i]["high"], candles[i]["low"]
        if all(candles[i-j]["high"] < h for j in range(1, n+1)) and \
           all(candles[i+j]["high"] < h for j in range(1, n+1)):
            sh.append({"idx": i, "price": h, "dt": candles[i]["datetime"]})
        if all(candles[i-j]["low"] > l for j in range(1, n+1)) and \
           all(candles[i+j]["low"] > l for j in range(1, n+1)):
            sl.append({"idx": i, "price": l, "dt": candles[i]["datetime"]})
    return sh, sl


def label_structure(swings_list):
    labeled = []
    prev_price = None
    for s in swings_list:
        if prev_price is None:
            lbl = s["type"]
        elif s["type"] == "H":
            if s["price"] > prev_price: lbl = "HH"
            elif s["price"] < prev_price: lbl = "LH"
            else: lbl = "EH"
        else:
            if s["price"] > prev_price: lbl = "HL"
            elif s["price"] < prev_price: lbl = "LL"
            else: lbl = "EL"
        s["label"] = lbl
        prev_price = s["price"]
        labeled.append(s)
    return labeled


def analyze_structure(candles):
    sh, sl = find_swings(candles, 3)
    all_swings = [{"type": "H", **s} for s in sh] + [{"type": "L", **s} for s in sl]
    all_swings.sort(key=lambda x: x["idx"])
    labeled = label_structure(all_swings)

    highs = [s for s in labeled if s["type"] == "H" and s["label"] in ("HH", "LH")]
    lows = [s for s in labeled if s["type"] == "L" and s["label"] in ("HL", "LL")]

    recent_h = highs[-3:] if len(highs) >= 3 else highs
    recent_l = lows[-3:] if len(lows) >= 3 else lows

    hh = sum(1 for s in recent_h if s["label"] == "HH")
    hl = sum(1 for s in recent_l if s["label"] == "HL")
    lh = sum(1 for s in recent_h if s["label"] == "LH")
    ll = sum(1 for s in recent_l if s["label"] == "LL")

    if hh >= 2 and hl >= 2:
        trend = "BULLISH"
    elif lh >= 2 and ll >= 2:
        trend = "BEARISH"
    else:
        trend = "NEUTRAL"

    return labeled, trend, sh, sl


