def detect_ob(candles):
    obs = []
    for i in range(2, len(candles) - 1):
        c = candles[i]
        # Bullish OB
        if c["close"] < c["open"]:
            future = candles[i+1:min(i+6, len(candles))]
            if future:
                move = max(f2["high"] for f2 in future) - c["low"]
                if move / c["low"] * 100 >= 0.05:
                    filled = any(
                        candles[j]["low"] <= c["high"] and candles[j]["close"] <= c["low"]
                        for j in range(i+6, len(candles))
                    )
                    if not filled:
                        obs.append({"type": "BULLISH", "top": c["high"], "bot": c["low"],
                                    "dt": c["datetime"]})
        # Bearish OB
        if c["close"] > c["open"]:
            future = candles[i+1:min(i+6, len(candles))]
            if future:
                move = c["high"] - min(f2["low"] for f2 in future)
                if move / c["high"] * 100 >= 0.05:
                    filled = any(
                        candles[j]["high"] >= c["high"] and candles[j]["close"] >= c["low"]
                        for j in range(i+6, len(candles))
                    )
                    if not filled:
                        obs.append({"type": "BEARISH", "top": c["high"], "bot": c["low"],
                                    "dt": c["datetime"]})
    return obs[-10:]


