def detect_fvg(candles):
    fvgs = []
    for i in range(1, len(candles) - 1):
        c1, c2, c3 = candles[i-1], candles[i], candles[i+1]
        avg = (c1["high"] + c1["low"]) / 2
        mg = avg * 0.0001
        # Bullish FVG
        if c1["high"] < c3["low"]:
            gap = c3["low"] - c1["high"]
            if gap >= mg:
                filled = any(
                    candles[j]["low"] <= c3["low"] and candles[j]["high"] >= c1["high"]
                    for j in range(i+2, len(candles))
                )
                if not filled:
                    fvgs.append({"type": "BULLISH", "top": c3["low"], "bot": c1["high"],
                                 "gap": gap, "dt": c2["datetime"]})
        # Bearish FVG
        if c1["low"] > c3["high"]:
            gap = c1["low"] - c3["high"]
            if gap >= mg:
                filled = any(
                    candles[j]["high"] >= c3["high"] and candles[j]["low"] <= c1["low"]
                    for j in range(i+2, len(candles))
                )
                if not filled:
                    fvgs.append({"type": "BEARISH", "top": c1["low"], "bot": c3["high"],
                                 "gap": gap, "dt": c2["datetime"]})
    return fvgs[-10:]


