def detect_liquidity(sh, sl):
    liqs = []
    # Equal Highs
    for i in range(len(sh)):
        for j in range(i+1, len(sh)):
            if abs(sh[i]["price"] - sh[j]["price"]) / sh[i]["price"] * 100 < 0.15:
                avg = (sh[i]["price"] + sh[j]["price"]) / 2
                liqs.append({"type": "EQH", "level": avg})
    # Equal Lows
    for i in range(len(sl)):
        for j in range(i+1, len(sl)):
            if abs(sl[i]["price"] - sl[j]["price"]) / sl[i]["price"] * 100 < 0.15:
                avg = (sl[i]["price"] + sl[j]["price"]) / 2
                liqs.append({"type": "EQL", "level": avg})
    # BSL / SSL
    for s in sh[-5:]:
        liqs.append({"type": "BSL", "level": s["price"]})
    for s in sl[-5:]:
        liqs.append({"type": "SSL", "level": s["price"]})
    return liqs


