def get_zone(price, swing_highs, swing_lows):
    if not swing_highs or not swing_lows:
        return "UNKNOWN", 0
    recent_high = max(s["price"] for s in swing_highs[-5:])
    recent_low = min(s["price"] for s in swing_lows[-5:])
    rng = recent_high - recent_low
    if rng == 0:
        return "UNKNOWN", 0
    fib = (price - recent_low) / rng
    if fib < 0.3:
        return "DEEP DISCOUNT", round(fib, 2)
    elif fib < 0.5:
        return "DISCOUNT", round(fib, 2)
    elif fib < 0.7:
        return "PREMIUM", round(fib, 2)
    else:
        return "DEEP PREMIUM", round(fib, 2)


