    if daily_trend == "BULLISH" and weekly_trend == "BULLISH":
        return "BULLISH", "Macro kuat bullish, HTF confirm ▲"
    elif daily_trend == "BEARISH" and weekly_trend == "BEARISH":
        return "BEARISH", "Macro kuat bearish, HTF confirm ▼"
    elif daily_trend == "BULLISH":
        return "BULLISH", "Daily bullish, weekly netral ▲"
    elif daily_trend == "BEARISH":
        return "BEARISH", "Daily bearish, weekly netral ▼"
    else:
        return "NEUTRAL", "Macro tidak jelas ─"


def smart_money_layer(obs, fvgs, liqs, price):
    """
    Smart Money Layer: OB, FVG, Liquidity Sweep
    """
    score = 0  # + = bullish, - = bearish

    # Nearest OB
    bull_obs = [o for o in obs if o["type"] == "BULLISH" and o["bot"] <= price <= o["top"] + 0.2]
    bear_obs = [o for o in obs if o["type"] == "BEARISH" and o["bot"] - 0.2 <= price <= o["top"]]

    if bull_obs:
        score += 2  # Price di bullish OB = strong buy signal
    if bear_obs:
        score -= 2  # Price di bearish OB = strong sell signal

    # Nearest FVG
    bull_fvgs = [f for f in fvgs if f["type"] == "BULLISH" and f["bot"] <= price <= f["top"] + 0.2]
    bear_fvgs = [f for f in fvgs if f["type"] == "BEARISH" and f["bot"] - 0.2 <= price <= f["top"]]

    if bull_fvgs:
        score += 1
    if bear_fvgs:
        score -= 1

    # Liquidity
    ssl_levels = [l for l in liqs if l["type"] == "SSL"]
    bsl_levels = [l for l in liqs if l["type"] == "BSL"]

    for ssl in ssl_levels:
        if price <= ssl["level"] + 0.05:
            score += 2  # SSL swept = bullish (institutions buy)

    for bsl in bsl_levels:
        if price >= bsl["level"] - 0.05:
            score -= 1  # Price di BSL = could reverse

    if score >= 2:
        return "BULLISH", f"Smart money accumulation (score: {score})"
    elif score <= -2:
        return "BEARISH", f"Smart money distribution (score: {score})"
    else:
        return "NEUTRAL", f"Smart money netral (score: {score})"


